# MainViewController.swift
import UIKit
import GoogleMaps

class MainViewController: UIViewController {
    
    private var mapView: GMSMapView!
    private var locationManager = CLLocationManager()
    private var pickupMarker: GMSMarker?
    private var destinationMarker: GMSMarker?
    private var pickupLocation: CLLocationCoordinate2D?
    private var destinationLocation: CLLocationCoordinate2D?
    private var estimatedPrice: Double = 0.0
    
    private let pickupButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Set Pickup Location", for: .normal)
        button.backgroundColor = .systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let destinationButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Set Destination", for: .normal)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        button.isEnabled = false
        button.alpha = 0.5
        return button
    }()
    
    private let bookRideButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Book Ride", for: .normal)
        button.backgroundColor = .systemOrange
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        button.isEnabled = false
        button.alpha = 0.5
        return button
    }()
    
    private let priceLabel: UILabel = {
        let label = UILabel()
        label.text = "Select locations to see price"
        label.textAlignment = .center
        label.font = UIFont.boldSystemFont(ofSize: 18)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        title = "Ride Booking"
        view.backgroundColor = .white
        
        setupMap()
        setupUI()
        setupLocationManager()
    }
    
    private func setupMap() {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12.0)
        mapView = GMSMapView.map(withFrame: .zero, camera: camera)
        mapView.translatesAutoresizingMaskIntoConstraints = false
        mapView.delegate = self
        view.addSubview(mapView)
        
        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            mapView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            mapView.heightAnchor.constraint(equalTo: view.heightAnchor, multiplier: 0.6)
        ])
    }
    
    private func setupUI() {
        view.addSubview(priceLabel)
        view.addSubview(pickupButton)
        view.addSubview(destinationButton)
        view.addSubview(bookRideButton)
        
        NSLayoutConstraint.activate([
            priceLabel.topAnchor.constraint(equalTo: mapView.bottomAnchor, constant: 20),
            priceLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            priceLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            pickupButton.topAnchor.constraint(equalTo: priceLabel.bottomAnchor, constant: 20),
            pickupButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            pickupButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            pickupButton.heightAnchor.constraint(equalToConstant: 50),
            
            destinationButton.topAnchor.constraint(equalTo: pickupButton.bottomAnchor, constant: 15),
            destinationButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            destinationButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            destinationButton.heightAnchor.constraint(equalToConstant: 50),
            
            bookRideButton.topAnchor.constraint(equalTo: destinationButton.bottomAnchor, constant: 15),
            bookRideButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            bookRideButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            bookRideButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        pickupButton.addTarget(self, action: #selector(setPickupTapped), for: .touchUpInside)
        destinationButton.addTarget(self, action: #selector(setDestinationTapped), for: .touchUpInside)
        bookRideButton.addTarget(self, action: #selector(bookRideTapped), for: .touchUpInside)
    }
    
    private func setupLocationManager() {
        locationManager.delegate = self
        locationManager.requestWhenInUseAuthorization()
        locationManager.startUpdatingLocation()
        mapView.isMyLocationEnabled = true
    }
    
    @objc private func setPickupTapped() {
        let alert = UIAlertController(title: "Set Pickup", message: "Tap on the map to set pickup location", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    @objc private func setDestinationTapped() {
        let alert = UIAlertController(title: "Set Destination", message: "Tap on the map to set destination", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    @objc private func bookRideTapped() {
        let paymentVC = PaymentViewController(amount: estimatedPrice)
        paymentVC.delegate = self
        let navController = UINavigationController(rootViewController: paymentVC)
        present(navController, animated: true)
    }
    
    private func calculatePrice() {
        guard let pickup = pickupLocation, let destination = destinationLocation else { return }
        
        let pickupLoc = CLLocation(latitude: pickup.latitude, longitude: pickup.longitude)
        let destLoc = CLLocation(latitude: destination.latitude, longitude: destination.longitude)
        let distance = pickupLoc.distance(from: destLoc) / 1609.34
        
        estimatedPrice = max(5.0, distance * 2.5 + 3.0)
        priceLabel.text = String(format: "Estimated Price: $%.2f", estimatedPrice)
        
        bookRideButton.isEnabled = true
        bookRideButton.alpha = 1.0
        
        drawRoute(from: pickup, to: destination)
    }
    
    private func drawRoute(from start: CLLocationCoordinate2D, to end: CLLocationCoordinate2D) {
        let path = GMSMutablePath()
        path.add(start)
        path.add(end)
        
        let polyline = GMSPolyline(path: path)
        polyline.strokeColor = .systemBlue
        polyline.strokeWidth = 3.0
        polyline.map = mapView
        
        let bounds = GMSCoordinateBounds(coordinate: start, coordinate: end)
        let update = GMSCameraUpdate.fit(bounds, withPadding: 100)
        mapView.animate(with: update)
    }
}

extension MainViewController: GMSMapViewDelegate {
    func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
        if pickupLocation == nil {
            pickupMarker?.map = nil
            pickupMarker = GMSMarker(position: coordinate)
            pickupMarker?.title = "Pickup"
            pickupMarker?.icon = GMSMarker.markerImage(with: .systemGreen)
            pickupMarker?.map = mapView
            pickupLocation = coordinate
            
            pickupButton.setTitle("✓ Pickup Set", for: .normal)
            destinationButton.isEnabled = true
            destinationButton.alpha = 1.0
        } else if destinationLocation == nil {
            destinationMarker?.map = nil
            destinationMarker = GMSMarker(position: coordinate)
            destinationMarker?.title = "Destination"
            destinationMarker?.icon = GMSMarker.markerImage(with: .systemRed)
            destinationMarker?.map = mapView
            destinationLocation = coordinate
            
            destinationButton.setTitle("✓ Destination Set", for: .normal)
            calculatePrice()
        }
    }
}

extension MainViewController: CLLocationManagerDelegate {
    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.first else { return }
        let camera = GMSCameraPosition.camera(withLatitude: location.coordinate.latitude, longitude: location.coordinate.longitude, zoom: 14.0)
        mapView.animate(to: camera)
        locationManager.stopUpdatingLocation()
    }
}

extension MainViewController: PaymentViewControllerDelegate {
    func paymentDidComplete(success: Bool) {
        if success {
            let alert = UIAlertController(title: "Success!", message: "Your ride has been booked!", preferredStyle: .alert)
            alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
                self.resetBooking()
            })
            present(alert, animated: true)
        }
    }
    
    private func resetBooking() {
        pickupMarker?.map = nil
        destinationMarker?.map = nil
        pickupLocation = nil
        destinationLocation = nil
        estimatedPrice = 0.0
        
        pickupButton.setTitle("Set Pickup Location", for: .normal)
        destinationButton.setTitle("Set Destination", for: .normal)
        destinationButton.isEnabled = false
        destinationButton.alpha = 0.5
        bookRideButton.isEnabled = false
        bookRideButton.alpha = 0.5
        priceLabel.text = "Select locations to see price"
    }
}

# PaymentViewController.swift
import UIKit

protocol PaymentViewControllerDelegate: AnyObject {
    func paymentDidComplete(success: Bool)
}

class PaymentViewController: UIViewController {
    
    weak var delegate: PaymentViewControllerDelegate?
    private let amount: Double
    private let stripePublishableKey = "pk_test_Stripe51234567890"
    
    private let cardNumberField: UITextField = {
        let field = UITextField()
        field.placeholder = "Card Number"
        field.borderStyle = .roundedRect
        field.keyboardType = .numberPad
        field.translatesAutoresizingMaskIntoConstraints = false
        return field
    }()
    
    private let expiryField: UITextField = {
        let field = UITextField()
        field.placeholder = "MM/YY"
        field.borderStyle = .roundedRect
        field.keyboardType = .numberPad
        field.translatesAutoresizingMaskIntoConstraints = false
        return field
    }()
    
    private let cvcField: UITextField = {
        let field = UITextField()
        field.placeholder = "CVC"
        field.borderStyle = .roundedRect
        field.keyboardType = .numberPad
        field.isSecureTextEntry = true
        field.translatesAutoresizingMaskIntoConstraints = false
        return field
    }()
    
    private let nameField: UITextField = {
        let field = UITextField()
        field.placeholder = "Cardholder Name"
        field.borderStyle = .roundedRect
        field.autocapitalizationType = .words
        field.translatesAutoresizingMaskIntoConstraints = false
        return field
    }()
    
    private let amountLabel: UILabel = {
        let label = UILabel()
        label.textAlignment = .center
        label.font = UIFont.boldSystemFont(ofSize: 24)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let payButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Pay Now", for: .normal)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let activityIndicator: UIActivityIndicatorView = {
        let indicator = UIActivityIndicatorView(style: .large)
        indicator.translatesAutoresizingMaskIntoConstraints = false
        indicator.hidesWhenStopped = true
        return indicator
    }()
    
    init(amount: Double) {
        self.amount = amount
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        title = "Payment"
        view.backgroundColor = .white
        
        navigationItem.leftBarButtonItem = UIBarButtonItem(barButtonSystemItem: .cancel, target: self, action: #selector(cancelTapped))
        
        setupUI()
        amountLabel.text = String(format: "Amount: $%.2f", amount)
    }
    
    private func setupUI() {
        view.addSubview(amountLabel)
        view.addSubview(cardNumberField)
        view.addSubview(expiryField)
        view.addSubview(cvcField)
        view.addSubview(nameField)
        view.addSubview(payButton)
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            amountLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 40),
            amountLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            amountLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            cardNumberField.topAnchor.constraint(equalTo: amountLabel.bottomAnchor, constant: 40),
            cardNumberField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            cardNumberField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            cardNumberField.heightAnchor.constraint(equalToConstant: 50),
            
            expiryField.topAnchor.constraint(equalTo: cardNumberField.bottomAnchor, constant: 15),
            expiryField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            expiryField.widthAnchor.constraint(equalTo: view.widthAnchor, multiplier: 0.45),
            expiryField.heightAnchor.constraint(equalToConstant: 50),
            
            cvcField.topAnchor.constraint(equalTo: cardNumberField.bottomAnchor, constant: 15),
            cvcField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            cvcField.widthAnchor.constraint(equalTo: view.widthAnchor, multiplier: 0.45),
            cvcField.heightAnchor.constraint(equalToConstant: 50),
            
            nameField.topAnchor.constraint(equalTo: expiryField.bottomAnchor, constant: 15),
            nameField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            nameField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            nameField.heightAnchor.constraint(equalToConstant: 50),
            
            payButton.topAnchor.constraint(equalTo: nameField.bottomAnchor, constant: 40),
            payButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            payButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            payButton.heightAnchor.constraint(equalToConstant: 50),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
        
        payButton.addTarget(self, action: #selector(payTapped), for: .touchUpInside)
    }
    
    @objc private func cancelTapped() {
        dismiss(animated: true)
    }
    
    @objc private func payTapped() {
        guard validateFields() else { return }
        
        processPayment()
    }
    
    private func validateFields() -> Bool {
        guard let cardNumber = cardNumberField.text, cardNumber.count >= 13 else {
            showAlert(message: "Please enter a valid card number")
            return false
        }
        
        guard let expiry = expiryField.text, expiry.count >= 4 else {
            showAlert(message: "Please enter a valid expiry date")
            return false
        }
        
        guard let cvc = cvcField.text, cvc.count >= 3 else {
            showAlert(message: "Please enter a valid CVC")
            return false
        }
        
        guard let name = nameField.text, !name.isEmpty else {
            showAlert(message: "Please enter cardholder name")
            return false
        }
        
        return true
    }
    
    private func processPayment() {
        activityIndicator.startAnimating()
        payButton.isEnabled = false
        
        DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) { [weak self] in
            guard let self = self else { return }
            
            self.activityIndicator.stopAnimating()
            self.payButton.isEnabled = true
            
            let success = self.simulatePayment()
            
            if success {
                self.dismiss(animated: true) {
                    self.delegate?.paymentDidComplete(success: true)
                }
            } else {
                self.showAlert(message: "Payment failed. Please try again.")
            }
        }
    }
    
    private func simulatePayment() -> Bool {
        let cardNumber = cardNumberField.text ?? ""
        return !cardNumber.hasPrefix("0000")
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

